mapper.select:
select a.tag_number, a.tag_name,a.tag_name_en, a.description, a.description_en, b.function_list from vehicle_function_three_tag a left join vehicle_function_tree b on a.id = b.function_three_tag_id and b.vehicle_id = #{vehicleId} where 1=1
and a.tag_number= #{tagNumber}
and a.tag_name like concat('%',#{tagName},'%')
